def _utc_stamp() -> str:
    return time.strftime("%Y%m%dT%H%M%SZ", time.gmtime())


def main() -> int:
    repo_root = Path.cwd()
    backup_root = repo_root / "tools" / f"_patch_backup_{PATCH_ID}_{_utc_stamp()}"
    backed_up_files: list[str] = []
    written_files: list[str] = []
    compile_errors: dict[str, str] = {}

    for rel, content in PAYLOAD_FILES.items():
        target = repo_root / rel
        if target.exists():
            backup_target = backup_root / rel
            backup_target.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(target, backup_target)
            backed_up_files.append(rel)
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text(content, encoding="utf-8", newline="\n")
        written_files.append(rel)

    for rel in written_files:
        if rel.endswith(".py"):
            try:
                py_compile.compile(str(repo_root / rel), doraise=True)
            except Exception as exc:
                compile_errors[rel] = str(exc)

    result = {
        "applied": not compile_errors,
        "patch_id": PATCH_ID,
        "patch_version": PATCH_VERSION,
        "patch_name": PATCH_NAME,
        "written_files": written_files,
        "backed_up_files": backed_up_files,
        "backup_root": str(backup_root.relative_to(repo_root)) if backed_up_files else "",
        "compile_errors": compile_errors,
        "py_compile_ok": not compile_errors,
        "archive_execution_allowed": False,
        "archive_move_performed": False,
        "file_delete_performed": False,
        "destructive_cleanup_performed": False,
        "exchange_submit_performed": False,
        "trading_action_performed": False,
        "training_performed": False,
        "reload_performed": False,
        "runtime_overlay_activated": False,
        "approved_for_exchange_submit": False,
        "approved_for_live_real": False,
        "approved_for_paper_transition": False,
        "approved_for_runtime_overlay": False,
    }
    print(json.dumps(result, indent=2, sort_keys=True, ensure_ascii=False))
    return 0 if not compile_errors else 1


if __name__ == "__main__":
    raise SystemExit(main())
